    { name: 'Выпечка', items: [
      { id: 3, name: 'Круассан', price: 210, img: '🥐', desc: 'Свежий, хрустящий, на масле' },
      { id: 7, name: 'Маффин', price: 180, img: '🧁', desc: 'С черникой и кремом' },
      { id: 8, name: 'Улитка с корицей', price: 195, img: '🥯', desc: 'Ароматная домашняя выпечка' }
