// --- НАВИГАЦИЯ ---
const BottomNav = () => {
  const loc = useLocation();
  return (
    <nav className="bottom-bar">
      <Link to="/" className={`nav-link ${loc.pathname === '/' ? 'active' : ''}`}>
        <span className="nav-icon">🍴</span>
        <span>Меню</span>
      </Link>
      <Link to="/profile" className={`nav-link ${loc.pathname === '/profile' ? 'active' : ''}`}>
        <span className="nav-icon">👤</span>
        <span>Профиль</span>
      </Link>
    </nav>
  );
};

export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    if (!user) return;
    const fetchOrders = () => {
      fetch(`http://localhost:8000/index.php?user_id=${user.id}`)
        .then(res => res.json()).then(data => setOrders(Array.isArray(data) ? data : []));
    };
    fetchOrders();
    const int = setInterval(fetchOrders, 4000);
    return () => clearInterval(int);
  }, [user]);

  const auth = async (action, body) => {
    const res = await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ action, ...body })});
    const data = await res.json();
    if (data.id) { setUser(data); localStorage.setItem('user', JSON.stringify(data)); } else { alert(data.error); }
  };

  const handleOrder = async () => {
    const desc = cart.map(i => i.name).join(', ');
    const total = cart.reduce((sum, i) => sum + i.price, 0);
    await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ user_id: user.id, description: desc, total_amount: total })});
    setCart([]);
    alert('Заказ отправлен в райскую кофейню!');
  };

  if (!user) return <AuthScreen 
    onLogin={(email, password) => auth('login', { email, password })} 
    onRegister={(name, email, password) => auth('register', { name, email, password })} 
  />;

  return (
    <Router>
      <div className="paradise-app">
        <Routes>
          <Route path="/" element={<Menu cart={cart} onAddToCart={i => setCart([...cart, i])} onRemoveFromCart={idx => setCart(cart.filter((_, i) => i !== idx))} onOrder={handleOrder} />} />
          <Route path="/profile" element={<Profile user={user} orders={orders} onLogout={() => {setUser(null); localStorage.removeItem('user');}} />} />
        </Routes>
        <BottomNav />
      </div>
    </Router>
  );
}
